class Solution:
    def doesAliceWin(self, s: str) -> bool:
        vowels = set('aeiou')
        count = 0
        for char in s:
            if char in vowels:
                count += 1
        return count % 2 != 0 or any(s[i] in vowels for i in range(len(s) - 1) if s[i+1] in vowels)
